using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [DataTestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentException(int quantity)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", 1, -5.00m));
    }

    [DataTestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void AddItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(sku!, 1, 10.00m));
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("SKU-MISSING"));
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_KeepsOtherItems()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _cart.AddItem("SKU-001", 2, 15.00m);
        _cart.AddItem("SKU-002", 1, 7.50m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected discounted total but got {total}");
    }

    [DataTestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_AppliedTwice_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("SAVE10"));
    }
}

